/**
 * Indonesia non-cooperative jurisdiction block (POJK 8/2023 Art. 36).
 *
 * OJK requires countermeasures (blocking) for FATF Call-for-Action
 * (black list) jurisdictions. Currently DPRK, Iran, and Myanmar.
 * This checks the creditor counterparty's legal entity
 * jurisdiction_cooperative flag — set false by compliance analyst
 * for entities in FATF black-list jurisdictions.
 *
 * Grey-list (Increased Monitoring) jurisdictions require EDD but
 * not blocking — those are NOT covered here.
 */
export const handler = async (input) => {
  const cp = input.creditor_counterparty;
  if (!cp) return { ledger_accounts: {} };

  const le = cp.legal_entity;
  if (!le) return { ledger_accounts: {} };

  if (le.jurisdiction_cooperative !== false) return { ledger_accounts: {} };

  const creditor = input.creditor_payment_account;
  if (!creditor) return { ledger_accounts: {} };

  const las = creditor.las || [];
  const ledger_accounts = {};
  for (const la of las) {
    ledger_accounts[la.id] = {
      daily_debit_cap: 0,
      daily_credit_cap: 0,
      reason: 'id_ncj_block',
      block_reason: 'id_ncj_block',
      is_blocked: true
    };
  }
  return { ledger_accounts };
};
